import React from 'react';

function Track({ name, color }) {
  return (
    <div className="track-row">
      <div className="track-header" style={{ background: color }}>
        <div className="track-name">{name}</div>
        <div className="track-controls">
          <button className="btn tiny">M</button>
          <button className="btn tiny">S</button>
        </div>
      </div>
      <div className="track-clip-area">{/* clips go here */}</div>
    </div>
  );
}

export default function TrackList() {
  const tracks = [
    { name: 'Drums', color: '#FFCDD2' },
    { name: 'Bass', color: '#C8E6C9' },
    { name: 'Keys', color: '#BBDEFB' },
    { name: 'Lead', color: '#E1BEE7' }
  ];

  return (
    <div className="tracklist">
      {tracks.map((t) => (
        <Track key={t.name} name={t.name} color={t.color} />
      ))}
    </div>
  );
}
